mapper.select:
select sart.id as rowId , sart.name as name,sart.sub_flag as subFlag, sart.title as title,sart.train_code as trainCode,sart.address,sart.start_date as startDate,sart.end_date as endDate, csru.name as sponsorUnitName, puser.name as parterName,sart.parter_duty as parterDuty, ccsti.name as parterTitleName, sdept.name as parterDeptName, sart.parter_account as parterAccount,sart.note as note,sart.expected_start_date as expectedStartDate, sart.expected_end_date as expectedEndDate,sart.train_number as trainNumber, sart.meeting_fee_amt as meetingFeeAmt,sart.material_fee_amt as materialFeeAmt, sart.hotel_fee_amt as hotelFeeAmt,sart.traffic_fee_amt as trafficFeeAmt,sart.other_fee_amt as otherFeeAmt, sart.funds_account as fundsAccount,sart.create_time,sart.sub_date,puser1.name as creatorName,puser2.name as subUserName from srm_ac_research_train sart left join ct_srm_rely_unit csru on csru.code=sart.sponsor_unit left join ct_srm_user puser on puser.id=sart.parter_id left join ct_srm_user puser1 on puser1.id=sart.creator left join ct_srm_user puser2 on puser2.id=sart.sub_user_id left join ct_srm_title_info ccsti on ccsti.code=sart.parter_title left join ct_srm_dept sdept on sdept.id=sart.parter_dept_id where (sart.sub_user_id=#{acResearchTrainDto.userId} or sart.creator=#{acResearchTrainDto.userId} )
and sart.sub_flag = #{acResearchTrainDto.subFlag}
and sart.name LIKE CONCAT('%', #{acResearchTrainDto.name}, '%')
and sart.sub_date >= #{acResearchTrainDto.startDate}
and sart.sub_date <= #{acResearchTrainDto.endDate}
order by sart.id desc
